/**
 * TanStack Start Server Functions Generator
 *
 * Generates CRUD server functions using createServerFn
 * for each Prisma model.
 */

import type { PrismaModel, PrismaField } from './prisma-generator'
import { toCamelCase, getIdField, getScalarFields } from './prisma-generator'

/**
 * Generate server functions code for all models
 */
export function generateServerFunctions(models: PrismaModel[]): string {
  const lines: string[] = [
    '/**',
    ' * Auto-generated Server Functions',
    ' *',
    ' * CRUD operations for TanStack Start.',
    ' * Generated by `shogo generate` - DO NOT EDIT',
    ' */',
    '',
    'import { createServerFn } from \'@tanstack/react-start\'',
    'import { shogo } from \'../lib/shogo\'',
    'import { hooks } from \'./hooks\'',
    'import type {',
  ]

  // Import types
  for (const model of models) {
    lines.push(`  ${model.name}Type,`)
    lines.push(`  ${model.name}CreateInput,`)
    lines.push(`  ${model.name}UpdateInput,`)
  }
  lines.push('} from \'./types\'')
  lines.push('')

  // Generate functions for each model
  for (const model of models) {
    lines.push(...generateModelFunctions(model))
  }

  return lines.join('\n')
}

/**
 * Generate CRUD functions for a single model
 */
function generateModelFunctions(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)
  const idField = getIdField(model)
  
  if (!idField) {
    return [`// Skipped ${name} - no @id field found`, '']
  }

  const lines: string[] = [
    `// ============================================================================`,
    `// ${name} Server Functions`,
    `// ============================================================================`,
    '',
  ]

  // LIST function
  lines.push(...generateListFunction(model))

  // GET function
  lines.push(...generateGetFunction(model))

  // CREATE function
  lines.push(...generateCreateFunction(model))

  // UPDATE function
  lines.push(...generateUpdateFunction(model))

  // DELETE function
  lines.push(...generateDeleteFunction(model))

  return lines
}

function generateListFunction(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)

  return [
    `/**`,
    ` * List all ${name} records`,
    ` */`,
    `export const get${name}List = createServerFn({ method: 'POST' })`,
    `  .inputValidator((data: { userId?: string; where?: Record<string, unknown> }) => data)`,
    `  .handler(async ({ data }) => {`,
    `    let where: Record<string, unknown> = data.where || {}`,
    ``,
    `    // Apply beforeList hook if defined`,
    `    const hook = hooks.${name}?.beforeList`,
    `    if (hook) {`,
    `      const hookResult = await hook({ userId: data.userId })`,
    `      if (hookResult?.where) {`,
    `        where = { ...where, ...hookResult.where }`,
    `      }`,
    `    }`,
    ``,
    `    const items = await shogo.db.${nameLower}.findMany({`,
    `      where,`,
    `      orderBy: { createdAt: 'desc' },`,
    `    })`,
    ``,
    `    return items as ${name}Type[]`,
    `  })`,
    '',
  ]
}

function generateGetFunction(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)

  return [
    `/**`,
    ` * Get a single ${name} by ID`,
    ` */`,
    `export const get${name}ById = createServerFn({ method: 'POST' })`,
    `  .inputValidator((data: { id: string; userId?: string }) => data)`,
    `  .handler(async ({ data }) => {`,
    `    // Apply beforeGet hook if defined`,
    `    const hook = hooks.${name}?.beforeGet`,
    `    if (hook) {`,
    `      const hookResult = await hook(data.id, { userId: data.userId })`,
    `      if (hookResult?.deny) {`,
    `        throw new Error('Access denied')`,
    `      }`,
    `    }`,
    ``,
    `    const item = await shogo.db.${nameLower}.findUnique({`,
    `      where: { id: data.id },`,
    `    })`,
    ``,
    `    if (!item) {`,
    `      throw new Error('${name} not found')`,
    `    }`,
    ``,
    `    return item as ${name}Type`,
    `  })`,
    '',
  ]
}

function generateCreateFunction(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)

  return [
    `/**`,
    ` * Create a new ${name}`,
    ` */`,
    `export const create${name} = createServerFn({ method: 'POST' })`,
    `  .inputValidator((data: { input: ${name}CreateInput; userId?: string }) => data)`,
    `  .handler(async ({ data }) => {`,
    `    let input = data.input`,
    ``,
    `    // Apply beforeCreate hook if defined`,
    `    const hook = hooks.${name}?.beforeCreate`,
    `    if (hook) {`,
    `      const hookResult = await hook(input, { userId: data.userId })`,
    `      if (hookResult) {`,
    `        input = hookResult`,
    `      }`,
    `    }`,
    ``,
    `    const item = await shogo.db.${nameLower}.create({`,
    `      data: input,`,
    `    })`,
    ``,
    `    // Apply afterCreate hook if defined`,
    `    const afterHook = hooks.${name}?.afterCreate`,
    `    if (afterHook) {`,
    `      await afterHook(item, { userId: data.userId })`,
    `    }`,
    ``,
    `    return item as ${name}Type`,
    `  })`,
    '',
  ]
}

function generateUpdateFunction(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)

  return [
    `/**`,
    ` * Update an existing ${name}`,
    ` */`,
    `export const update${name} = createServerFn({ method: 'POST' })`,
    `  .inputValidator((data: { id: string; input: ${name}UpdateInput; userId?: string }) => data)`,
    `  .handler(async ({ data }) => {`,
    `    let input = data.input`,
    ``,
    `    // Apply beforeUpdate hook if defined`,
    `    const hook = hooks.${name}?.beforeUpdate`,
    `    if (hook) {`,
    `      const hookResult = await hook(data.id, input, { userId: data.userId })`,
    `      if (hookResult?.deny) {`,
    `        throw new Error('Access denied')`,
    `      }`,
    `      if (hookResult?.input) {`,
    `        input = hookResult.input`,
    `      }`,
    `    }`,
    ``,
    `    const item = await shogo.db.${nameLower}.update({`,
    `      where: { id: data.id },`,
    `      data: input,`,
    `    })`,
    ``,
    `    // Apply afterUpdate hook if defined`,
    `    const afterHook = hooks.${name}?.afterUpdate`,
    `    if (afterHook) {`,
    `      await afterHook(item, { userId: data.userId })`,
    `    }`,
    ``,
    `    return item as ${name}Type`,
    `  })`,
    '',
  ]
}

function generateDeleteFunction(model: PrismaModel): string[] {
  const name = model.name
  const nameLower = toCamelCase(name)

  return [
    `/**`,
    ` * Delete a ${name}`,
    ` */`,
    `export const delete${name} = createServerFn({ method: 'POST' })`,
    `  .inputValidator((data: { id: string; userId?: string }) => data)`,
    `  .handler(async ({ data }) => {`,
    `    // Apply beforeDelete hook if defined`,
    `    const hook = hooks.${name}?.beforeDelete`,
    `    if (hook) {`,
    `      const hookResult = await hook(data.id, { userId: data.userId })`,
    `      if (hookResult?.deny) {`,
    `        throw new Error('Access denied')`,
    `      }`,
    `    }`,
    ``,
    `    await shogo.db.${nameLower}.delete({`,
    `      where: { id: data.id },`,
    `    })`,
    ``,
    `    // Apply afterDelete hook if defined`,
    `    const afterHook = hooks.${name}?.afterDelete`,
    `    if (afterHook) {`,
    `      await afterHook(data.id, { userId: data.userId })`,
    `    }`,
    ``,
    `    return { success: true }`,
    `  })`,
    '',
  ]
}
